def NAND(a: int, b: int) -> int:
    return 1 - (a & b)

def NOT_nand(a: int) -> int:
    """NOT = NAND(A, A)"""
    return NAND(a, a)

def AND_nand(a: int, b: int) -> int:
    """AND = NOT(NAND(A, B))"""
    nand_ab = NAND(a, b)
    return NAND(nand_ab, nand_ab)

def OR_nand(a: int, b: int) -> int:
    """OR = NAND(NOT(A), NOT(B))"""
    not_a = NAND(a, a)
    not_b = NAND(b, b)
    return NAND(not_a, not_b)

def XOR_nand(a: int, b: int) -> int:
    """XOR using 4 NANDs"""
    nand_ab = NAND(a, b)
    nand_a_nab = NAND(a, nand_ab)
    nand_b_nab = NAND(b, nand_ab)
    return NAND(nand_a_nab, nand_b_nab)

def XNOR_nand(a: int, b: int) -> int:
    """XNOR = NOT(XOR)"""
    xor_result = XOR_nand(a, b)
    return NAND(xor_result, xor_result)

# Count gates used
print("Gate counts:")
print("  NOT: 1 NAND")
print("  AND: 2 NANDs")
print("  OR:  3 NANDs")
print("  XOR: 4 NANDs")
print("  XNOR: 5 NANDs")

print("\nTesting NAND-only implementations:")
all_correct = True
for a in [0, 1]:
    for b in [0, 1]:
        tests = [
            ("AND", AND_nand(a,b), a&b),
            ("OR", OR_nand(a,b), a|b),
            ("XOR", XOR_nand(a,b), a^b),
            ("XNOR", XNOR_nand(a,b), 1-(a^b)),
        ]
        for name, computed, expected in tests:
            if computed != expected:
                print(f"FAIL: {name}({a},{b}) = {computed}, expected {expected}")
                all_correct = False

for a in [0, 1]:
    if NOT_nand(a) != 1-a:
        print(f"FAIL: NOT({a})")
        all_correct = False

if all_correct:
    print("All tests passed! ✓")

