exercises.solution:
def NOR(a: int, b: int) -> int:
    return 1 - (a | b)

def NOT_nor(a: int) -> int:
    """NOT = NOR(A, A)"""
    return NOR(a, a)

def OR_nor(a: int, b: int) -> int:
    """OR = NOT(NOR(A, B))"""
    nor_ab = NOR(a, b)
    return NOR(nor_ab, nor_ab)

def AND_nor(a: int, b: int) -> int:
    """AND = NOR(NOT(A), NOT(B))"""
    not_a = NOR(a, a)
    not_b = NOR(b, b)
    return NOR(not_a, not_b)

def XOR_nor(a: int, b: int) -> int:
    """XOR using NOR gates"""
    # XOR = (A OR B) AND (NOT(A) OR NOT(B))
    # = (A OR B) AND (NOT(A AND B))
    or_ab = OR_nor(a, b)
    and_ab = AND_nor(a, b)
    not_and_ab = NOT_nor(and_ab)
    return AND_nor(or_ab, not_and_ab)

def NAND_nor(a: int, b: int) -> int:
    """NAND = NOT(AND)"""
    and_ab = AND_nor(a, b)
    return NOT_nor(and_ab)

# Count gates
print("Gate counts from NOR:")
print("  NOT: 1 NOR")
print("  OR:  2 NORs")
print("  AND: 3 NORs")
print("  XOR: 5 NORs")

print("\nTesting NOR-only implementations:")
all_correct = True
for a in [0, 1]:
    for b in [0, 1]:
        tests = [
            ("AND", AND_nor(a,b), a&b),
            ("OR", OR_nor(a,b), a|b),
            ("XOR", XOR_nor(a,b), a^b),
            ("NAND", NAND_nor(a,b), 1-(a&b)),
        ]
        for name, computed, expected in tests:
            if computed != expected:
                print(f"FAIL: {name}({a},{b}) = {computed}, expected {expected}")
                all_correct = False

if all_correct:
    print("All tests passed! ✓")
